import Technology from '@/types/Technology';
import { Globe } from 'lucide-react';
import Image from 'next/image';

export default async function StackSection() {
  async function fetchStack() {
    const response = await fetch(`${process.env.API_URL}/technologies`);
    const { data } = await response.json();
    return data;
  }
  const technologies: Technology[] = await fetchStack();
  return (
    <section className="flex flex-col items-center lg:items-start">
      <h2 className="flex items-center gap-2 font-semibold">
        <Globe className="scale-105 text-primary transition-all duration-300 hover:scale-110 hover:rotate-6 xl:scale-125" />{' '}
        Tech Stack
      </h2>
      <ul className="flex">
        {technologies &&
          technologies.map((technology) => (
            <li className="flex flex-col items-center p-2" key={technology.id}>
              <Image
                src={technology.logo.imageLink}
                alt={`Logo ${technology.name}`}
                width={40}
                height={40}
                className="m-2"
              />
              <h4 className="font-anton uppercase">{technology.name}</h4>
            </li>
          ))}
      </ul>
    </section>
  );
}
