import { BriefcaseBusiness } from 'lucide-react';
import ExperienceCard from './ExperienceCard';

export default async function ExperiencesSection() {
  async function fetchExperiences() {
    const response = await fetch(`${process.env.API_URL}/experiences`, {
      cache: 'no-store',
      headers: {
        'Content-Type': 'application/json'
      }
    });
    const { data } = await response.json();
    return data;
  }

  const data = await fetchExperiences();
  const lastExperience = data.splice(0, 1)[0];

  return (
    <section className="flex flex-col items-center lg:items-start">
      <h2 className="mb-12 flex items-center gap-2 text-center font-semibold lg:text-start">
        {' '}
        <BriefcaseBusiness className="scale-105 text-primary transition-all duration-300 hover:scale-110 hover:rotate-6 xl:scale-125" />
        Minhas experiências
      </h2>
      {lastExperience && (
        <ExperienceCard
          key={lastExperience.id}
          isLastExperience
          experience={lastExperience}
        />
      )}
      
      {data.map((experience: Experience) => (
        <ExperienceCard key={experience.id} experience={experience} />
      ))}
    </section>
  );
}
